import{_ as e,c as r,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"이용약관: 서비스 규칙 | OpenCodeDocs","description":"OpenCodeDocs 이용약관의 서비스 사용 규칙, 지식재산권 귀속 및 면책 조항을 알아보고, 양측의 권리와 의무를 명확히 합니다.","frontmatter":{"title":"이용약관: 서비스 규칙 | OpenCodeDocs","sidebarTitle":"5분 안에 규칙 이해하기","subtitle":"이용약관: 서비스 규칙","description":"OpenCodeDocs 이용약관의 서비스 사용 규칙, 지식재산권 귀속 및 면책 조항을 알아보고, 양측의 권리와 의무를 명확히 합니다."},"headers":[],"relativePath":"ko/terms.md","filePath":"ko/terms.md"}'),o={name:"ko/terms.md"};function i(n,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="사용자-서비스-약관" tabindex="-1">사용자 서비스 약관 <a class="header-anchor" href="#사용자-서비스-약관" aria-label="Permalink to &quot;사용자 서비스 약관&quot;">​</a></h1><p>최종 업데이트 일자: 2026-01-01 발효 일자: 2026-01-01</p><p>OpenCodeDocs를 이용해 주셔서 감사합니다! 저희 서비스를 사용하기 전에 본 사용자 서비스 약관(이하 &quot;본 약관&quot;)을 주의 깊게 읽어보시기 바랍니다. 저희 서비스를 사용하는 것은 본 약관의 규정에 동의하는 것을 의미합니다.</p><h2 id="_1-서비스-설명" tabindex="-1">1. 서비스 설명 <a class="header-anchor" href="#_1-서비스-설명" aria-label="Permalink to &quot;1. 서비스 설명&quot;">​</a></h2><p>OpenCodeDocs는 AI 도구 튜토리얼에 특화된 오픈 플랫폼으로, 다음과 같은 서비스를 제공합니다:</p><ul><li><strong>튜토리얼 콘텐츠</strong>: 오픈 소스 AI 도구(Claude Code, Cursor, LangChain 등) 사용 튜토리얼</li><li><strong>코드 검증</strong>: 소스 코드 저장소를 기반으로 튜토리얼 코드의 실행 가능성을 자동으로 검증</li><li><strong>커뮤니티 기능</strong>: 사용자는 GitHub를 통해 콘텐츠 기여 및 토론에 참여할 수 있음</li></ul><p>저희는 사전 통지 없이 언제든지 전체 또는 일부 서비스를 수정, 일시 중지 또는 종료할 권리를 보유합니다.</p><h2 id="_2-계정-등록-및-관리" tabindex="-1">2. 계정 등록 및 관리 <a class="header-anchor" href="#_2-계정-등록-및-관리" aria-label="Permalink to &quot;2. 계정 등록 및 관리&quot;">​</a></h2><h3 id="등록-조건" tabindex="-1">등록 조건 <a class="header-anchor" href="#등록-조건" aria-label="Permalink to &quot;등록 조건&quot;">​</a></h3><ul><li>만 16세 이상이어야 합니다(또는 거주 국가의 법적 성인 연령 도달)</li><li>정확하고 진실한 등록 정보를 제공해야 합니다</li><li>사용자마다 하나의 계정만 등록할 수 있습니다</li></ul><h3 id="계정-보안" tabindex="-1">계정 보안 <a class="header-anchor" href="#계정-보안" aria-label="Permalink to &quot;계정 보안&quot;">​</a></h3><ul><li>계정 자격 증명을 안전하게 관리할 책임은 사용자에게 있으며, 타인과 공유해서는 안 됩니다</li><li>계정이 도용당한 것을 발견하면 즉시 저희에게 연락해 주십시오</li><li>계정 관리 부실로 인한 손실은 사용자가 부담해야 합니다</li></ul><h3 id="계정-삭제" tabindex="-1">계정 삭제 <a class="header-anchor" href="#계정-삭제" aria-label="Permalink to &quot;계정 삭제&quot;">​</a></h3><p>언제든지 계정 삭제를 신청할 수 있습니다. 삭제 후 개인 데이터는 30일 이내에 삭제되지만, 공개적으로 게시된 콘텐츠는 보존될 수 있습니다.</p><h2 id="_3-사용자-행동-규범" tabindex="-1">3. 사용자 행동 규범 <a class="header-anchor" href="#_3-사용자-행동-규범" aria-label="Permalink to &quot;3. 사용자 행동 규범&quot;">​</a></h2><p>본 플랫폼을 사용할 때 다음과 같은 행위에 동의하지 않습니다:</p><ul><li>불법적, 유해적, 위협적, 괴롭힘, 명예훼손 또는 침해적인 콘텐츠 게시</li><li>타인을 사칭하거나 신원을 거짓으로 진술</li><li>승인 없이 타인의 계정 또는 시스템에 액세스</li><li>서비스의 정상적인 운영을 방해하거나 파괴</li><li>자동화된 도구로 대규모 콘텐츠 스크래핑(합리적인 API 사용 제외)</li><li>라이선스 계약을 준수하지 않고 튜토리얼 콘텐츠를 상업적 목적으로 사용</li></ul><h2 id="_4-지식재산권" tabindex="-1">4. 지식재산권 <a class="header-anchor" href="#_4-지식재산권" aria-label="Permalink to &quot;4. 지식재산권&quot;">​</a></h2><h3 id="오픈-소스-라이선스-설명" tabindex="-1">오픈 소스 라이선스 설명 <a class="header-anchor" href="#오픈-소스-라이선스-설명" aria-label="Permalink to &quot;오픈 소스 라이선스 설명&quot;">​</a></h3><ul><li><strong>튜토리얼 콘텐츠</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a> 라이선스를 채택하여, 비상업적 공유 및 개조를 허용하지만 저작자 표기 및 동일한 방식으로 공유해야 함</li><li><strong>웹사이트 구축</strong>: 본 프로젝트는 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>를 기반으로 구축되었으며 MIT 라이선스를 준수함</li><li><strong>사용자 기여</strong>: 제출한 콘텐츠는 상기 라이선스를 준수하는 전제 하에 플랫폼에서 사용할 수 있도록 기본적으로 라이선스가 부여됨</li></ul><p>OpenCodeDocs의 상표, 로고 및 기타 브랜드 식별자는 법적으로 보호되며, 승인 없이 사용할 수 없습니다.</p><h2 id="_5-면책-조항" tabindex="-1">5. 면책 조항 <a class="header-anchor" href="#_5-면책-조항" aria-label="Permalink to &quot;5. 면책 조항&quot;">​</a></h2><ul><li><strong>서비스 중단</strong>: 저희는 서비스의 중단 없는 운영이나 오류가 없음을 보장하지 않습니다. 유지보수, 업그레이드 또는 불가항력으로 인한 서비스 중단에 대해 책임을 지지 않습니다</li><li><strong>콘텐츠 정확성</strong>: 튜토리얼 콘텐츠는 참고용으로만 제공되며, 모든 환경에서의 사용 가능성을 보장하지 않습니다</li><li><strong>코드 사용 위험</strong>: 튜토리얼의 코드를 실행하는 것은 사용자의 책임이며, 격리된 환경에서 테스트하는 것을 권장합니다</li><li><strong>제3자 링크</strong>: 본 사이트에는 제3자 웹사이트에 대한 링크가 포함될 수 있으며, 해당 콘텐츠에 대해 책임을 지지 않습니다</li></ul><h2 id="_6-약관-수정" tabindex="-1">6. 약관 수정 <a class="header-anchor" href="#_6-약관-수정" aria-label="Permalink to &quot;6. 약관 수정&quot;">​</a></h2><p>저희는 수시로 본 약관을 수정할 수 있습니다. 수정된 약관은 웹사이트에 게시되며, 다음과 같은 방법으로 통지됩니다:</p><ul><li>웹사이트의 눈에 띄는 위치에 공지</li><li>등록된 이메일로 통지(해당되는 경우)</li></ul><p>서비스를 계속 사용하는 것은 수정된 약관에 동의하는 것을 의미합니다. 수정에 동의하지 않으시는 경우 서비스 사용을 중단하십시오.</p><h2 id="_7-분쟁-해결" tabindex="-1">7. 분쟁 해결 <a class="header-anchor" href="#_7-분쟁-해결" aria-label="Permalink to &quot;7. 분쟁 해결&quot;">​</a></h2><ul><li><strong>적용 법률</strong>: 본 약관은 중화인민공화국 법률의 적용을 받습니다</li><li><strong>분쟁 해결</strong>: 당사자 간에 우호적으로 협의하여 분쟁을 해결해야 합니다. 협의가 성립되지 않을 경우, 어느 당사자든 피고 소재지의 관할권을 가진 인민법원에 소송을 제기할 수 있습니다</li></ul><h2 id="_8-연락처" tabindex="-1">8. 연락처 <a class="header-anchor" href="#_8-연락처" aria-label="Permalink to &quot;8. 연락처&quot;">​</a></h2><p>본 약관에 대해 질문이 있으시면 다음으로 연락해 주십시오:</p><ul><li><strong>이메일</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const g=e(o,[["render",i]]);export{p as __pageData,g as default};
